});

const PlayerStateSchema = z
  .strictObject({
    hp: z.strictObject({
      current: z.number().int().nonnegative().max(bounds.playerCharacter.hpCap),
      max: z.number().int().positive().max(bounds.playerCharacter.hpCap),
