    withPlayerPosition(state, hoard?.position ?? { x: -1, y: -1 }),
    { kind: "take_hoard" },
    provider
  );
  expect(won.ok).toBe(true);
  if (!won.ok) {
    throw new Error(won.error.message);
  }

  return won.state;
};

