259	  expect(Array.isArray(parsed.events)).toBe(true);
260	  expect(typeof parsed.stateHash).toBe("string");
261	  return parsed as TraceTurnLine<RunAction, RunEvent>;
262	};
263	
264	const isRecord = (value: unknown): value is Record<string, unknown> =>
265	  value !== null && typeof value === "object" && !Array.isArray(value);
266	
267	class MemoryTraceFs implements TraceFsAdapter {
268	  readonly dirs: string[] = [];
269	  readonly files = new Map<string, string>();
270	
271	  makeDir(path: string): void {
272	    this.dirs.push(path);
273	  }
274	
275	  writeNewFile(path: string, contents: string): void {
276	    if (this.files.has(path)) {
277	      throw new Error(`file already exists: ${path}`);
278	    }
279	    this.files.set(path, contents);
280	  }
281	
282	  appendFile(path: string, contents: string): void {
283	    const current = this.files.get(path);
284	    if (current === undefined) {
285	      throw new Error(`file does not exist: ${path}`);
286	    }
287	    this.files.set(path, current + contents);
288	  }
289	
290	  read(path: string): string {
291	    const contents = this.files.get(path);
292	    if (contents === undefined) {
293	      throw new Error(`file does not exist: ${path}`);
294	    }
295	    return contents;
296	  }
297	}
